Greedy insertion with cost delta tracking: try each existing assign, compute cost increase, choose minimal positive delta; if none feasible, create new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	existingAssignIndices := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		existingAssignIndices = append(existingAssignIndices, i)
	}
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		id := total_ship + shipIdx
		bestAssignIdx := -1
		minDelta := math.MaxFloat64
		for _, idx := range existingAssignIndices {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			ok := assign.AddShip(id, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				if newCost >= 0 && delta >= 0 && delta < minDelta {
					minDelta = delta
					bestAssignIdx = idx
				}
				assign.RemoveShip(id)
				assign.GenRoute()
			}
		}
		if bestAssignIdx >= 0 {
			dispatch.Assigns[bestAssignIdx].AddShip(id, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				ok := assign.AddShip(id, ori, des)
				if ok {
					assign.GenRoute()
					if dispatch.AssignsLen < MAXASSIGNS {
						dispatch.AssignsLen++
						existingAssignIndices = append(existingAssignIndices, dispatch.AssignsLen-1)
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

